    Wish = apps.get_model("booking", "Wish")

    # member_id -> eindeutiger membership_id (None, wenn 0 oder >1 Anteile)
    sole = {}
    for member_id, membership_id in Share.objects.values_list("member_id", "membership_id"):
        if member_id in sole:
            sole[member_id] = None          # mehr als ein Anteil -> nicht eindeutig
        else:
            sole[member_id] = membership_id
    sole = {mid: ms for mid, ms in sole.items() if ms is not None}

    for model in (Allocation, Wish):
        updates = []
        for obj in model.objects.filter(membership__isnull=True).only("id", "member_id"):
            ms = sole.get(obj.member_id)
            if ms is not None:
                obj.membership_id = ms
                updates.append(obj)
        if updates:
            model.objects.bulk_update(updates, ["membership"], batch_size=500)


